package com.tschanz.aigeny.llm_tool.jira;

import com.tschanz.aigeny.config.JiraConfiguration;
import com.tschanz.aigeny.llm.model.ToolDefinition;
import com.tschanz.aigeny.llm_tool.AbstractTool;
import com.tschanz.aigeny.llm_tool.ToolResult;
import com.tschanz.aigeny.llm_tool.jira.http.JiraHttpClient;
import com.tschanz.aigeny.Messages;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.net.URLEncoder;
import java.net.http.HttpResponse;
import java.nio.charset.StandardCharsets;
import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

/**
 * Tool that clones an existing Jira issue.
 * It reads the source issue (and optionally its subtasks) during execute(),
 * then queues a CREATE_ISSUE action for user confirmation.
 */
@Service
public class CloneJiraIssueTool extends AbstractTool {

    private static final Logger log = LoggerFactory.getLogger(CloneJiraIssueTool.class);
    private static final int MAX_SUBTASKS = 20;

    // ── Message keys ─────────────────────────────────────────────────────────
    private static final String MSG_NOT_CONFIGURED   = "jira.error.not_configured_de";
    private static final String MSG_NO_TOKEN         = "jira.error.no_token";
    private static final String MSG_MISSING_KEY      = "jira.clone.missing_key";
    private static final String MSG_SOURCE_NOT_FOUND = "jira.error.issue_not_found";
    private static final String MSG_AUTH_FAILED      = "jira.error.auth_failed_en";
    private static final String MSG_HTTP_ERROR       = "jira.error.http_en";
    private static final String MSG_QUEUED           = "jira.clone.queued";
    private static final String MSG_QUEUED_SUBTASKS  = "jira.clone.queued_with_subtasks";
    private static final String MSG_WRITE_DISABLED   = "jira.write.mode_disabled";
    private static final String MSG_NO_STREAMING     = "jira.error.no_streaming_context";

    private final JiraConfiguration jiraConfig;
    private final JiraHttpClient jiraHttpClient;
    private final ConfirmationService confirmationService;

    public CloneJiraIssueTool(JiraConfiguration jiraConfig,
                              ObjectMapper objectMapper,
                              JiraHttpClient jiraHttpClient,
                              ConfirmationService confirmationService) {
        super(objectMapper);
        this.jiraConfig          = jiraConfig;
        this.jiraHttpClient      = jiraHttpClient;
        this.confirmationService = confirmationService;
    }

    @Override public String getName() { return "clone_jira_issue"; }
    @Override public boolean requiresConfirmation() { return true; }

    @Override
    public String getCallDescription(String argumentsJson) {
        try {
            JsonNode args = objectMapper.readTree(argumentsJson);
            String source = args.path("sourceIssueKey").asText("?");
            String target = args.path("targetProject").asText("").trim();
            boolean subtasks = args.path("cloneSubtasks").asBoolean(false);
            String base = "Jira-Ticket klonen: " + source + (target.isBlank() ? "" : " → " + target);
            return subtasks ? base + " (inkl. Sub-Tasks)" : base;
        } catch (Exception ignored) {}
        return "Jira-Ticket klonen";
    }

    @Override
    public String getDescription() {
        return "Clone an existing Jira issue. Reads the source issue and queues the creation of a copy for user confirmation. " +
               "IMPORTANT: Only works when Jira write mode is enabled in the UI sidebar (toggle 'Jira Schreiben'). " +
               "If write mode is disabled, the tool returns an error - do NOT ask for confirmation in that case. " +
               "Required: 'sourceIssueKey' (e.g. NOVA-12345). " +
               "Optional: 'targetProject' to clone into a different project (default: same project as source), " +
               "'summaryOverride' to change the summary (default: 'Clone of <original summary>'), " +
               "'assignee' to override the assignee (technical username), " +
               "'cloneSubtasks' (boolean, default false) to also clone all sub-tasks of the issue.";
    }

    @Override
    public ToolDefinition getDefinition() {
        Map<String, Object> propsMap = new LinkedHashMap<>();
        propsMap.put("sourceIssueKey",  Map.of("type", "string",  "description", "The Jira issue key to clone, e.g. NOVA-12345"));
        propsMap.put("targetProject",   Map.of("type", "string",  "description", "Target project key (default: same as source issue)"));
        propsMap.put("summaryOverride", Map.of("type", "string",  "description", "Override the summary of the clone (default: 'Clone of <original summary>')"));
        propsMap.put("assignee",        Map.of("type", "string",  "description", "Technical Jira username to assign the clone to (default: same as source)"));
        propsMap.put("cloneSubtasks",   Map.of("type", "boolean", "description", "Also clone all sub-tasks of the issue (default: false)"));
        return new ToolDefinition(getName(), getDescription(),
                Map.of("type", "object", "properties", propsMap, "required", new String[]{"sourceIssueKey"}));
    }

    @Override
    public ToolResult execute(String argumentsJson) throws Exception {
        if (!JiraWriteContext.isEnabled()) {
            return new ToolResult(Messages.get(MSG_WRITE_DISABLED));
        }

                String baseUrl = jiraConfig.getBaseUrl() == null ? "" : jiraConfig.getBaseUrl().replaceAll("/$", "");
        if (baseUrl.isBlank()) {
            return new ToolResult(Messages.get(MSG_NOT_CONFIGURED));
        }

        String token = JiraTokenContext.get();
        if (token == null || token.isBlank()) token = jiraConfig.getToken();
        if (token == null || token.isBlank()) {
            return new ToolResult(Messages.get(MSG_NO_TOKEN));
        }
        String auth = "Bearer " + token;

        JsonNode args           = objectMapper.readTree(argumentsJson);
        String sourceKey        = args.path("sourceIssueKey").asText("").trim();
        String targetProject    = args.path("targetProject").asText("").trim();
        String summaryOverride  = args.path("summaryOverride").asText("").trim();
        String assigneeOverride = args.path("assignee").asText("").trim();
        boolean cloneSubtasks   = args.path("cloneSubtasks").asBoolean(false);

        if (sourceKey.isBlank()) {
            return new ToolResult(Messages.get(MSG_MISSING_KEY));
        }

        // ── Fetch source issue ──────────────────────────────────────────────
        String fetchUrl = baseUrl + "/rest/api/2/issue/"
                + URLEncoder.encode(sourceKey, StandardCharsets.UTF_8)
                + "?fields=summary,description,issuetype,priority,assignee,project,subtasks";
        log.info(">> JIRA GET (clone source) {}", fetchUrl);

        JsonNode source = getJson(fetchUrl, auth);
        if (source == null) return new ToolResult(Messages.get(MSG_HTTP_ERROR, "?", "Request failed"));

        // handle error nodes set via sentinel
        if (source.has("_error")) {
            int status = source.path("_status").asInt(0);
            if (status == 404) return new ToolResult(Messages.get(MSG_SOURCE_NOT_FOUND, sourceKey));
            if (status == 401) return new ToolResult(Messages.get(MSG_AUTH_FAILED));
            return new ToolResult(Messages.get(MSG_HTTP_ERROR, status, source.path("_body").asText("")));
        }

        JsonNode fields = source.path("fields");

        // ── Derive clone fields ─────────────────────────────────────────────
        String srcProjectKey = fields.path("project").path("key").asText("");
        String projectKey    = targetProject.isBlank() ? srcProjectKey : targetProject;
        String srcSummary    = fields.path("summary").asText("");
        String summary       = summaryOverride.isBlank() ? "Clone of " + srcSummary : summaryOverride;
        String issuetype     = fields.path("issuetype").path("name").asText("Task");
        String description   = fields.path("description").asText("").trim();
        String srcAssignee   = fields.path("assignee").path("name").asText("");
        String assignee      = assigneeOverride.isBlank() ? srcAssignee : assigneeOverride;

        // ── Optionally fetch sub-tasks ──────────────────────────────────────
        List<Map<String, String>> subtaskList = new ArrayList<>();
        JsonNode subtasksNode = fields.path("subtasks");
        if (cloneSubtasks && subtasksNode.isArray() && !subtasksNode.isEmpty()) {
            int count = Math.min(subtasksNode.size(), MAX_SUBTASKS);
            log.info("   Fetching {} sub-task(s) for clone", count);
            for (int i = 0; i < count; i++) {
                String stKey = subtasksNode.get(i).path("key").asText();
                String stFetchUrl = baseUrl + "/rest/api/2/issue/"
                        + URLEncoder.encode(stKey, StandardCharsets.UTF_8)
                        + "?fields=summary,description,issuetype,assignee";
                JsonNode stNode = getJson(stFetchUrl, auth);
                if (stNode == null || stNode.has("_error")) {
                    log.warn("   Could not fetch subtask {}, skipping", stKey);
                    continue;
                }
                JsonNode stFields = stNode.path("fields");
                Map<String, String> st = new LinkedHashMap<>();
                st.put("summary",     stFields.path("summary").asText(""));
                st.put("issuetype",   stFields.path("issuetype").path("name").asText("Sub-task"));
                st.put("description", stFields.path("description").asText("").trim());
                st.put("assignee",    assigneeOverride.isBlank()
                        ? stFields.path("assignee").path("name").asText("")
                        : assigneeOverride);
                subtaskList.add(st);
            }
        }

        // ── Build params & queue ────────────────────────────────────────────
        Map<String, Object> params = new LinkedHashMap<>();
        params.put("projectKey",  projectKey);
        params.put("summary",     summary);
        params.put("issuetype",   issuetype);
        if (!description.isBlank()) params.put("description", description);
        if (!assignee.isBlank())    params.put("assignee", assignee);
        params.put("clonedFrom",  sourceKey);
        if (!subtaskList.isEmpty()) params.put("subtasks", subtaskList);

        // ── Human description ───────────────────────────────────────────────
        StringBuilder humanDesc = new StringBuilder("Jira-Ticket **" + sourceKey + "** klonen");
        if (!targetProject.isBlank() && !targetProject.equals(srcProjectKey)) {
            humanDesc.append(" → Projekt **").append(projectKey).append("**");
        }
        humanDesc.append(":\n");
        humanDesc.append("- **Typ**: ").append(issuetype).append("\n");
        humanDesc.append("- **Summary**: ").append(summary).append("\n");
        if (!assignee.isBlank()) humanDesc.append("- **Assignee**: ").append(assignee).append("\n");
        if (!subtaskList.isEmpty()) {
            humanDesc.append("- **Sub-Tasks**: ").append(subtaskList.size()).append(" werden ebenfalls geklont\n");
        }

        if (!confirmationService.isAvailable()) {
            return new ToolResult(Messages.get(MSG_NO_STREAMING));
        }

        log.info("Requesting confirmation for clone_jira_issue {} → project={} subtasks={}",
                sourceKey, projectKey, subtaskList.size());
        return confirmationService.requestConfirmation(
                humanDesc.toString(),
                new PendingJiraAction(PendingJiraAction.ActionType.CREATE_ISSUE, null, params, humanDesc.toString()));
    }

    /** Fetches a URL and returns the parsed JSON, or a sentinel node with _error/_status/_body on failure. */
    private JsonNode getJson(String url, String auth) {
        try {
            HttpResponse<String> resp = jiraHttpClient.get(url, auth);
            if (resp.statusCode() == 200) {
                return objectMapper.readTree(resp.body());
            }
            // Return sentinel error node
            return objectMapper.createObjectNode()
                    .put("_error", true)
                    .put("_status", resp.statusCode())
                    .put("_body", resp.body());
        } catch (Exception e) {
            log.error("Error fetching {}: {}", url, e.getMessage());
            return null;
        }
    }
}

package com.tschanz.aigeny.llm_tool.jira;

import com.tschanz.aigeny.config.JiraConfiguration;
import com.tschanz.aigeny.llm.model.ToolDefinition;
import com.tschanz.aigeny.llm_tool.AbstractTool;
import com.tschanz.aigeny.llm_tool.ToolResult;
import com.tschanz.aigeny.llm_tool.jira.http.JiraHttpClient;
import com.tschanz.aigeny.Messages;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.net.URLEncoder;
import java.net.http.HttpResponse;
import java.nio.charset.StandardCharsets;
import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

/**
 * Tool that clones an existing Jira issue.
 * It reads the source issue (and optionally its subtasks) during execute(),
 * then queues a CREATE_ISSUE action for user confirmation.
 */
@Service
public class CloneJiraIssueTool extends AbstractTool {

    private static final Logger log = LoggerFactory.getLogger(CloneJiraIssueTool.class);
    private static final int MAX_SUBTASKS = 20;

    // ── Message keys ─────────────────────────────────────────────────────────
    private static final String MSG_NOT_CONFIGURED   = "jira.error.not_configured_de";
    private static final String MSG_NO_TOKEN         = "jira.error.no_token";
    private static final String MSG_MISSING_KEY      = "jira.clone.missing_key";
    private static final String MSG_SOURCE_NOT_FOUND = "jira.error.issue_not_found";
    private static final String MSG_AUTH_FAILED      = "jira.error.auth_failed_en";
    private static final String MSG_HTTP_ERROR       = "jira.error.http_en";
    private static final String MSG_WRITE_DISABLED   = "jira.write.mode_disabled";
    private static final String MSG_NO_STREAMING     = "jira.error.no_streaming_context";

    private final JiraConfiguration jiraConfig;
    private final JiraHttpClient jiraHttpClient;
    private final ConfirmationService confirmationService;

    public CloneJiraIssueTool(JiraConfiguration jiraConfig,
                              ObjectMapper objectMapper,
                              JiraHttpClient jiraHttpClient,
                              ConfirmationService confirmationService) {
        super(objectMapper);
        this.jiraConfig          = jiraConfig;
        this.jiraHttpClient      = jiraHttpClient;
        this.confirmationService = confirmationService;
    }

    @Override public String getName() { return "clone_jira_issue"; }
    @Override public boolean requiresConfirmation() { return true; }

    @Override
    public String getCallDescription(String argumentsJson) {
        try {
            JsonNode args = objectMapper.readTree(argumentsJson);
            String source = args.path("sourceIssueKey").asText("?");
            String target = args.path("targetProject").asText("").trim();
            boolean subtasks = args.path("cloneSubtasks").asBoolean(false);
            String base = "Jira-Ticket klonen: " + source + (target.isBlank() ? "" : " → " + target);
            return subtasks ? base + " (inkl. Sub-Tasks)" : base;
        } catch (Exception ignored) {}
        return "Jira-Ticket klonen";
    }

    @Override
    public String getDescription() {
        return "Clone an existing Jira issue. Reads the source issue and queues the creation of a copy for user confirmation. " +
               "IMPORTANT: Only works when Jira write mode is enabled in the UI sidebar (toggle 'Jira Schreiben'). " +
               "If write mode is disabled, the tool returns an error - do NOT ask for confirmation in that case. " +
               "Required: 'sourceIssueKey' (e.g. NOVA-12345). " +
               "Optional: 'targetProject' to clone into a different project (default: same project as source), " +
               "'summaryOverride' to change the summary (default: 'Clone of <original summary>'), " +
               "'assignee' to override the assignee (technical username), " +
               "'cloneSubtasks' (boolean, default false) to also clone all sub-tasks of the issue.";
    }

    @Override
    public ToolDefinition getDefinition() {
        Map<String, Object> propsMap = new LinkedHashMap<>();
        propsMap.put("sourceIssueKey",  Map.of("type", "string",  "description", "The Jira issue key to clone, e.g. NOVA-12345"));
        propsMap.put("targetProject",   Map.of("type", "string",  "description", "Target project key (default: same as source issue)"));
        propsMap.put("summaryOverride", Map.of("type", "string",  "description", "Override the summary of the clone (default: 'Clone of <original summary>')"));
        propsMap.put("assignee",        Map.of("type", "string",  "description", "Technical Jira username to assign the clone to (default: same as source)"));
        propsMap.put("cloneSubtasks",   Map.of("type", "boolean", "description", "Also clone all sub-tasks of the issue (default: false)"));
        return new ToolDefinition(getName(), getDescription(),
                Map.of("type", "object", "properties", propsMap, "required", new String[]{"sourceIssueKey"}));
    }

    @Override
    public ToolResult execute(String argumentsJson) throws Exception {
        if (!JiraWriteContext.isEnabled()) {
            return new ToolResult(Messages.get(MSG_WRITE_DISABLED));
        }

        String baseUrl = jiraConfig.getBaseUrl() == null ? "" : jiraConfig.getBaseUrl().replaceAll("/$", "");
        if (baseUrl.isBlank()) {
            return new ToolResult(Messages.get(MSG_NOT_CONFIGURED));
        }

        String token = JiraTokenContext.get();
        if (token == null || token.isBlank()) token = jiraConfig.getToken();
        if (token == null || token.isBlank()) {
            return new ToolResult(Messages.get(MSG_NO_TOKEN));
        }
        String auth = "Bearer " + token;

        JsonNode args           = objectMapper.readTree(argumentsJson);
        String sourceKey        = args.path("sourceIssueKey").asText("").trim();
        String targetProject    = args.path("targetProject").asText("").trim();
        String summaryOverride  = args.path("summaryOverride").asText("").trim();
        String assigneeOverride = args.path("assignee").asText("").trim();
        boolean cloneSubtasks   = args.path("cloneSubtasks").asBoolean(false);

        if (sourceKey.isBlank()) {
            return new ToolResult(Messages.get(MSG_MISSING_KEY));
        }

        // ── Fetch source issue ──────────────────────────────────────────────
        String fetchUrl = baseUrl + "/rest/api/2/issue/"
                + URLEncoder.encode(sourceKey, StandardCharsets.UTF_8)
                + "?fields=summary,description,issuetype,priority,assignee,project,subtasks";
        log.info(">> JIRA GET (clone source) {}", fetchUrl);

        HttpResponse<String> sourceResp = jiraHttpClient.get(fetchUrl, auth);
        if (sourceResp.statusCode() == 404) return new ToolResult(Messages.get(MSG_SOURCE_NOT_FOUND, sourceKey));
        if (sourceResp.statusCode() == 401) return new ToolResult(Messages.get(MSG_AUTH_FAILED));
        if (sourceResp.statusCode() != 200) {
            return new ToolResult(Messages.get(MSG_HTTP_ERROR, sourceResp.statusCode(), sourceResp.body()));
        }

        JsonNode fields = objectMapper.readTree(sourceResp.body()).path("fields");

        // ── Derive clone fields ─────────────────────────────────────────────
        String srcProjectKey = fields.path("project").path("key").asText("");
        String projectKey    = targetProject.isBlank() ? srcProjectKey : targetProject;
        String srcSummary    = fields.path("summary").asText("");
        String summary       = summaryOverride.isBlank() ? "Clone of " + srcSummary : summaryOverride;
        String issuetype     = fields.path("issuetype").path("name").asText("Task");
        String description   = fields.path("description").asText("").trim();
        String srcAssignee   = fields.path("assignee").path("name").asText("");
        String assignee      = assigneeOverride.isBlank() ? srcAssignee : assigneeOverride;

        // ── Optionally fetch sub-tasks ──────────────────────────────────────
        List<Map<String, String>> subtaskList = new ArrayList<>();
        JsonNode subtasksNode = fields.path("subtasks");
        if (cloneSubtasks && subtasksNode.isArray() && !subtasksNode.isEmpty()) {
            int count = Math.min(subtasksNode.size(), MAX_SUBTASKS);
            log.info("   Fetching {} sub-task(s) for clone", count);
            for (int i = 0; i < count; i++) {
                String stKey = subtasksNode.get(i).path("key").asText();
                String stFetchUrl = baseUrl + "/rest/api/2/issue/"
                        + URLEncoder.encode(stKey, StandardCharsets.UTF_8)
                        + "?fields=summary,description,issuetype,assignee";
                try {
                    HttpResponse<String> stResp = jiraHttpClient.get(stFetchUrl, auth);
                    if (stResp.statusCode() != 200) {
                        log.warn("   Could not fetch subtask {} (status {}), skipping", stKey, stResp.statusCode());
                        continue;
                    }
                    JsonNode stFields = objectMapper.readTree(stResp.body()).path("fields");
                    Map<String, String> st = new LinkedHashMap<>();
                    st.put("summary",     stFields.path("summary").asText(""));
                    st.put("issuetype",   stFields.path("issuetype").path("name").asText("Sub-task"));
                    st.put("description", stFields.path("description").asText("").trim());
                    st.put("assignee",    assigneeOverride.isBlank()
                            ? stFields.path("assignee").path("name").asText("")
                            : assigneeOverride);
                    subtaskList.add(st);
                } catch (Exception e) {
                    log.warn("   Error fetching subtask {}, skipping: {}", stKey, e.getMessage());
                }
            }
        }

        // ── Build params & queue ────────────────────────────────────────────
        Map<String, Object> params = new LinkedHashMap<>();
        params.put("projectKey",  projectKey);
        params.put("summary",     summary);
        params.put("issuetype",   issuetype);
        if (!description.isBlank()) params.put("description", description);
        if (!assignee.isBlank())    params.put("assignee", assignee);
        params.put("clonedFrom",  sourceKey);
        if (!subtaskList.isEmpty()) params.put("subtasks", subtaskList);

        // ── Human description ───────────────────────────────────────────────
        StringBuilder humanDesc = new StringBuilder("Jira-Ticket **" + sourceKey + "** klonen");
        if (!targetProject.isBlank() && !targetProject.equals(srcProjectKey)) {
            humanDesc.append(" → Projekt **").append(projectKey).append("**");
        }
        humanDesc.append(":\n");
        humanDesc.append("- **Typ**: ").append(issuetype).append("\n");
        humanDesc.append("- **Summary**: ").append(summary).append("\n");
        if (!assignee.isBlank()) humanDesc.append("- **Assignee**: ").append(assignee).append("\n");
        if (!subtaskList.isEmpty()) {
            humanDesc.append("- **Sub-Tasks**: ").append(subtaskList.size()).append(" werden ebenfalls geklont\n");
        }

        if (!confirmationService.isAvailable()) {
            return new ToolResult(Messages.get(MSG_NO_STREAMING));
        }

        log.info("Requesting confirmation for clone_jira_issue {} → project={} subtasks={}",
                sourceKey, projectKey, subtaskList.size());
        return confirmationService.requestConfirmation(
                humanDesc.toString(),
                new PendingJiraAction(PendingJiraAction.ActionType.CREATE_ISSUE, null, params, humanDesc.toString()));
    }
}

package com.tschanz.aigeny.llm_tool.jira;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.tschanz.aigeny.config.JiraConfiguration;
import com.tschanz.aigeny.llm_tool.ToolResult;
import com.tschanz.aigeny.llm_tool.jira.http.JiraHttpClient;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import java.net.http.HttpResponse;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.ArgumentMatchers.contains;
import static org.mockito.Mockito.*;
import static org.mockito.Mockito.when;

/**
 * Unit tests for {@link CloneJiraIssueTool}.
 *
 * <p>Verifies that:
 * <ul>
 *   <li>The tool uses the injected {@link JiraHttpClient} (D-4 fix – no longer creates
 *       its own {@code java.net.http.HttpClient})</li>
 *   <li>The tool uses the injected {@link ConfirmationService} instead of the static
 *       {@link ConfirmationContext} (D-1 fix)</li>
 *   <li>Configuration and authorisation guards work correctly</li>
 *   <li>Write-mode guard blocks execution when Jira write mode is disabled</li>
 * </ul>
 */
@ExtendWith(MockitoExtension.class)
@DisplayName("CloneJiraIssueTool")
class CloneJiraIssueToolTest {

    @Mock private JiraConfiguration jiraConfig;
    @Mock private JiraHttpClient jiraHttpClient;
    @Mock private ConfirmationService confirmationService;
    @Mock private HttpResponse<String> httpResponse;

    private CloneJiraIssueTool tool;
    private final ObjectMapper objectMapper = new ObjectMapper();

    private static final String SOURCE_ISSUE_JSON = """
            {
              "key": "NOVA-100",
              "fields": {
                "summary":     "Original Issue",
                "description": "Some description",
                "issuetype":   { "name": "Task" },
                "priority":    { "name": "Medium" },
                "assignee":    { "name": "u123456", "displayName": "Alice" },
                "project":     { "key": "NOVA" },
                "subtasks":    []
              }
            }""";

    @BeforeEach
    void setUp() {
        tool = new CloneJiraIssueTool(jiraConfig, objectMapper, jiraHttpClient, confirmationService);
        // lenient: tests that check write-mode guard never reach getBaseUrl()
        lenient().when(jiraConfig.getBaseUrl()).thenReturn("https://jira.example.com");
        JiraTokenContext.set("test-token");
        JiraWriteContext.set(true);
    }

    @AfterEach
    void tearDown() {
        JiraTokenContext.clear();
        JiraWriteContext.set(false);
    }

    // ── Configuration and authorisation guards ────────────────────────────────

    @Nested
    @DisplayName("Configuration guards")
    class ConfigurationGuards {

        @Test
        @DisplayName("returns error and does not call HTTP client when write mode is disabled")
        void returnsErrorWhenWriteModeDisabled() throws Exception {
            JiraWriteContext.set(false);

            ToolResult result = tool.execute("{\"sourceIssueKey\":\"NOVA-100\"}");

            assertThat(result.getText()).isNotBlank();
            verifyNoInteractions(jiraHttpClient);
        }

        @Test
        @DisplayName("returns error when base URL is blank")
        void returnsErrorWhenBaseUrlBlank() throws Exception {
            when(jiraConfig.getBaseUrl()).thenReturn("");

            ToolResult result = tool.execute("{\"sourceIssueKey\":\"NOVA-100\"}");

            assertThat(result.getText()).isNotBlank();
            verifyNoInteractions(jiraHttpClient);
        }

        @Test
        @DisplayName("returns error when no token is available")
        void returnsErrorWhenNoToken() throws Exception {
            JiraTokenContext.clear();
            when(jiraConfig.getToken()).thenReturn(null);

            ToolResult result = tool.execute("{\"sourceIssueKey\":\"NOVA-100\"}");

            assertThat(result.getText()).isNotBlank();
            verifyNoInteractions(jiraHttpClient);
        }

        @Test
        @DisplayName("returns error when sourceIssueKey is missing")
        void returnsErrorWhenSourceKeyMissing() throws Exception {
            ToolResult result = tool.execute("{}");

            assertThat(result.getText()).isNotBlank();
            verifyNoInteractions(jiraHttpClient);
        }
    }

    // ── Injected JiraHttpClient usage (D-4) ───────────────────────────────────

    @Nested
    @DisplayName("Uses injected JiraHttpClient (D-4)")
    class UsesInjectedHttpClient {

        @Test
        @DisplayName("calls jiraHttpClient.get() with source issue key in URL")
        void callsJiraHttpClientWithSourceKey() throws Exception {
            when(httpResponse.statusCode()).thenReturn(200);
            when(httpResponse.body()).thenReturn(SOURCE_ISSUE_JSON);
            when(jiraHttpClient.get(anyString(), anyString())).thenReturn(httpResponse);
            // confirmationService not available → tool returns "no_streaming_context" after HTTP call
            when(confirmationService.isAvailable()).thenReturn(false);

            tool.execute("{\"sourceIssueKey\":\"NOVA-100\"}");

            verify(jiraHttpClient).get(contains("NOVA-100"), anyString());
        }

        @Test
        @DisplayName("uses Bearer token from ThreadLocal in HTTP requests")
        void usesBearerToken() throws Exception {
            when(httpResponse.statusCode()).thenReturn(200);
            when(httpResponse.body()).thenReturn(SOURCE_ISSUE_JSON);
            when(jiraHttpClient.get(anyString(), anyString())).thenReturn(httpResponse);
            when(confirmationService.isAvailable()).thenReturn(false);

            tool.execute("{\"sourceIssueKey\":\"NOVA-100\"}");

            verify(jiraHttpClient).get(anyString(), contains("Bearer test-token"));
        }

        @Test
        @DisplayName("returns error result when source issue is not found (404)")
        void returnsErrorOn404() throws Exception {
            when(httpResponse.statusCode()).thenReturn(404);
            when(httpResponse.body()).thenReturn("Not Found");
            when(jiraHttpClient.get(anyString(), anyString())).thenReturn(httpResponse);

            ToolResult result = tool.execute("{\"sourceIssueKey\":\"NOVA-MISSING\"}");

            assertThat(result.getText()).isNotBlank();
        }

        @Test
        @DisplayName("returns error result when Jira returns 401")
        void returnsErrorOn401() throws Exception {
            when(httpResponse.statusCode()).thenReturn(401);
            when(httpResponse.body()).thenReturn("Unauthorized");
            when(jiraHttpClient.get(anyString(), anyString())).thenReturn(httpResponse);

            ToolResult result = tool.execute("{\"sourceIssueKey\":\"NOVA-100\"}");

            assertThat(result.getText()).isNotBlank();
        }
    }

    // ── Injected ConfirmationService usage (D-1) ──────────────────────────────

    @Nested
    @DisplayName("Uses injected ConfirmationService (D-1)")
    class UsesInjectedConfirmationService {

        @Test
        @DisplayName("returns no-streaming error when confirmationService.isAvailable() is false")
        void returnsErrorWhenConfirmationServiceNotAvailable() throws Exception {
            when(httpResponse.statusCode()).thenReturn(200);
            when(httpResponse.body()).thenReturn(SOURCE_ISSUE_JSON);
            when(jiraHttpClient.get(anyString(), anyString())).thenReturn(httpResponse);
            when(confirmationService.isAvailable()).thenReturn(false);

            ToolResult result = tool.execute("{\"sourceIssueKey\":\"NOVA-100\"}");

            assertThat(result.getText()).isNotBlank();
            verify(confirmationService, never()).requestConfirmation(anyString(), any());
        }

        @Test
        @DisplayName("delegates to confirmationService.requestConfirmation() when available")
        void delegatesToConfirmationServiceWhenAvailable() throws Exception {
            when(httpResponse.statusCode()).thenReturn(200);
            when(httpResponse.body()).thenReturn(SOURCE_ISSUE_JSON);
            when(jiraHttpClient.get(anyString(), anyString())).thenReturn(httpResponse);
            when(confirmationService.isAvailable()).thenReturn(true);
            ToolResult expected = new ToolResult("confirmed!");
            when(confirmationService.requestConfirmation(anyString(), any())).thenReturn(expected);

            ToolResult result = tool.execute("{\"sourceIssueKey\":\"NOVA-100\"}");

            assertThat(result).isSameAs(expected);
            verify(confirmationService).requestConfirmation(contains("NOVA-100"), any(PendingJiraAction.class));
        }
    }
}

package com.tschanz.aigeny.llm_tool.jira;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.tschanz.aigeny.config.JiraConfiguration;
import com.tschanz.aigeny.llm_tool.ToolResult;
import com.tschanz.aigeny.llm_tool.jira.http.JiraHttpClient;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import java.net.http.HttpResponse;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.ArgumentMatchers.contains;
import static org.mockito.Mockito.*;
import static org.mockito.Mockito.when;

/**
 * Unit tests for {@link CloneJiraIssueTool}.
 *
 * <p>Verifies that:
 * <ul>
 *   <li>The tool uses the injected {@link JiraHttpClient} – no own {@code java.net.http.HttpClient}
 *       and no sentinel-node pattern (S-3 / D-4 fix)</li>
 *   <li>The tool uses the injected {@link ConfirmationService} instead of the static
 *       {@link ConfirmationContext} (D-1 fix)</li>
 *   <li>Configuration and authorisation guards work correctly</li>
 *   <li>Write-mode guard blocks execution when Jira write mode is disabled</li>
 *   <li>Subtask cloning fetches each sub-task via the injected HTTP client</li>
 * </ul>
 */
@ExtendWith(MockitoExtension.class)
@DisplayName("CloneJiraIssueTool")
class CloneJiraIssueToolTest {

    @Mock private JiraConfiguration jiraConfig;
    @Mock private JiraHttpClient jiraHttpClient;
    @Mock private ConfirmationService confirmationService;
    @Mock private HttpResponse<String> httpResponse;

    private CloneJiraIssueTool tool;
    private final ObjectMapper objectMapper = new ObjectMapper();

    private static final String SOURCE_ISSUE_JSON = """
            {
              "key": "NOVA-100",
              "fields": {
                "summary":     "Original Issue",
                "description": "Some description",
                "issuetype":   { "name": "Task" },
                "priority":    { "name": "Medium" },
                "assignee":    { "name": "u123456", "displayName": "Alice" },
                "project":     { "key": "NOVA" },
                "subtasks":    []
              }
            }""";

    @BeforeEach
    void setUp() {
        tool = new CloneJiraIssueTool(jiraConfig, objectMapper, jiraHttpClient, confirmationService);
        // lenient: tests that check write-mode guard never reach getBaseUrl()
        lenient().when(jiraConfig.getBaseUrl()).thenReturn("https://jira.example.com");
        JiraTokenContext.set("test-token");
        JiraWriteContext.set(true);
    }

    @AfterEach
    void tearDown() {
        JiraTokenContext.clear();
        JiraWriteContext.set(false);
    }

    // ── Configuration and authorisation guards ────────────────────────────────

    @Nested
    @DisplayName("Configuration guards")
    class ConfigurationGuards {

        @Test
        @DisplayName("returns error and does not call HTTP client when write mode is disabled")
        void returnsErrorWhenWriteModeDisabled() throws Exception {
            JiraWriteContext.set(false);

            ToolResult result = tool.execute("{\"sourceIssueKey\":\"NOVA-100\"}");

            assertThat(result.getText()).isNotBlank();
            verifyNoInteractions(jiraHttpClient);
        }

        @Test
        @DisplayName("returns error when base URL is blank")
        void returnsErrorWhenBaseUrlBlank() throws Exception {
            when(jiraConfig.getBaseUrl()).thenReturn("");

            ToolResult result = tool.execute("{\"sourceIssueKey\":\"NOVA-100\"}");

            assertThat(result.getText()).isNotBlank();
            verifyNoInteractions(jiraHttpClient);
        }

        @Test
        @DisplayName("returns error when no token is available")
        void returnsErrorWhenNoToken() throws Exception {
            JiraTokenContext.clear();
            when(jiraConfig.getToken()).thenReturn(null);

            ToolResult result = tool.execute("{\"sourceIssueKey\":\"NOVA-100\"}");

            assertThat(result.getText()).isNotBlank();
            verifyNoInteractions(jiraHttpClient);
        }

        @Test
        @DisplayName("returns error when sourceIssueKey is missing")
        void returnsErrorWhenSourceKeyMissing() throws Exception {
            ToolResult result = tool.execute("{}");

            assertThat(result.getText()).isNotBlank();
            verifyNoInteractions(jiraHttpClient);
        }
    }

    // ── Injected JiraHttpClient usage (D-4) ───────────────────────────────────

    @Nested
    @DisplayName("Uses injected JiraHttpClient (D-4)")
    class UsesInjectedHttpClient {

        @Test
        @DisplayName("calls jiraHttpClient.get() with source issue key in URL")
        void callsJiraHttpClientWithSourceKey() throws Exception {
            when(httpResponse.statusCode()).thenReturn(200);
            when(httpResponse.body()).thenReturn(SOURCE_ISSUE_JSON);
            when(jiraHttpClient.get(anyString(), anyString())).thenReturn(httpResponse);
            // confirmationService not available → tool returns "no_streaming_context" after HTTP call
            when(confirmationService.isAvailable()).thenReturn(false);

            tool.execute("{\"sourceIssueKey\":\"NOVA-100\"}");

            verify(jiraHttpClient).get(contains("NOVA-100"), anyString());
        }

        @Test
        @DisplayName("uses Bearer token from ThreadLocal in HTTP requests")
        void usesBearerToken() throws Exception {
            when(httpResponse.statusCode()).thenReturn(200);
            when(httpResponse.body()).thenReturn(SOURCE_ISSUE_JSON);
            when(jiraHttpClient.get(anyString(), anyString())).thenReturn(httpResponse);
            when(confirmationService.isAvailable()).thenReturn(false);

            tool.execute("{\"sourceIssueKey\":\"NOVA-100\"}");

            verify(jiraHttpClient).get(anyString(), contains("Bearer test-token"));
        }

        @Test
        @DisplayName("returns error result when source issue is not found (404)")
        void returnsErrorOn404() throws Exception {
            when(httpResponse.statusCode()).thenReturn(404);
            when(jiraHttpClient.get(anyString(), anyString())).thenReturn(httpResponse);

            ToolResult result = tool.execute("{\"sourceIssueKey\":\"NOVA-MISSING\"}");

            assertThat(result.getText()).isNotBlank();
        }

        @Test
        @DisplayName("returns error result when Jira returns 401")
        void returnsErrorOn401() throws Exception {
            when(httpResponse.statusCode()).thenReturn(401);
            when(jiraHttpClient.get(anyString(), anyString())).thenReturn(httpResponse);

            ToolResult result = tool.execute("{\"sourceIssueKey\":\"NOVA-100\"}");

            assertThat(result.getText()).isNotBlank();
        }
    }

    // ── Injected ConfirmationService usage (D-1) ──────────────────────────────

    @Nested
    @DisplayName("Uses injected ConfirmationService (D-1)")
    class UsesInjectedConfirmationService {

        @Test
        @DisplayName("returns no-streaming error when confirmationService.isAvailable() is false")
        void returnsErrorWhenConfirmationServiceNotAvailable() throws Exception {
            when(httpResponse.statusCode()).thenReturn(200);
            when(httpResponse.body()).thenReturn(SOURCE_ISSUE_JSON);
            when(jiraHttpClient.get(anyString(), anyString())).thenReturn(httpResponse);
            when(confirmationService.isAvailable()).thenReturn(false);

            ToolResult result = tool.execute("{\"sourceIssueKey\":\"NOVA-100\"}");

            assertThat(result.getText()).isNotBlank();
            verify(confirmationService, never()).requestConfirmation(anyString(), any());
        }

        @Test
        @DisplayName("delegates to confirmationService.requestConfirmation() when available")
        void delegatesToConfirmationServiceWhenAvailable() throws Exception {
            when(httpResponse.statusCode()).thenReturn(200);
            when(httpResponse.body()).thenReturn(SOURCE_ISSUE_JSON);
            when(jiraHttpClient.get(anyString(), anyString())).thenReturn(httpResponse);
            when(confirmationService.isAvailable()).thenReturn(true);
            ToolResult expected = new ToolResult("confirmed!");
            when(confirmationService.requestConfirmation(anyString(), any())).thenReturn(expected);

            ToolResult result = tool.execute("{\"sourceIssueKey\":\"NOVA-100\"}");

            assertThat(result).isSameAs(expected);
            verify(confirmationService).requestConfirmation(contains("NOVA-100"), any(PendingJiraAction.class));
        }
    }

    // ── Subtask cloning ───────────────────────────────────────────────────────

    @Nested
    @DisplayName("Subtask cloning")
    class SubtaskCloning {

        private static final String SOURCE_WITH_SUBTASKS_JSON = """
                {
                  "key": "NOVA-100",
                  "fields": {
                    "summary":     "Parent Issue",
                    "description": "",
                    "issuetype":   { "name": "Story" },
                    "assignee":    { "name": "u123456", "displayName": "Alice" },
                    "project":     { "key": "NOVA" },
                    "subtasks": [
                      { "key": "NOVA-101" },
                      { "key": "NOVA-102" }
                    ]
                  }
                }""";

        private static final String SUBTASK_JSON = """
                {
                  "key": "NOVA-101",
                  "fields": {
                    "summary":   "Sub-task A",
                    "issuetype": { "name": "Sub-task" },
                    "assignee":  { "name": "u123456" },
                    "description": ""
                  }
                }""";

        @Test
        @DisplayName("fetches each subtask via jiraHttpClient when cloneSubtasks=true")
        void fetchesEachSubtaskViaHttpClient() throws Exception {
            HttpResponse<String> parentResp   = mockResponseWith(200, SOURCE_WITH_SUBTASKS_JSON);
            HttpResponse<String> subtaskResp  = mockResponseWith(200, SUBTASK_JSON);

            when(jiraHttpClient.get(contains("NOVA-100"), anyString())).thenReturn(parentResp);
            when(jiraHttpClient.get(contains("NOVA-101"), anyString())).thenReturn(subtaskResp);
            when(jiraHttpClient.get(contains("NOVA-102"), anyString())).thenReturn(subtaskResp);
            when(confirmationService.isAvailable()).thenReturn(true);
            when(confirmationService.requestConfirmation(anyString(), any())).thenReturn(new ToolResult("ok"));

            tool.execute("{\"sourceIssueKey\":\"NOVA-100\",\"cloneSubtasks\":true}");

            verify(jiraHttpClient).get(contains("NOVA-101"), anyString());
            verify(jiraHttpClient).get(contains("NOVA-102"), anyString());
        }

        @Test
        @DisplayName("confirmation description mentions subtask count when cloneSubtasks=true")
        void confirmationMentionsSubtaskCount() throws Exception {
            HttpResponse<String> parentResp   = mockResponseWith(200, SOURCE_WITH_SUBTASKS_JSON);
            HttpResponse<String> subtaskResp  = mockResponseWith(200, SUBTASK_JSON);

            when(jiraHttpClient.get(contains("NOVA-100"), anyString())).thenReturn(parentResp);
            when(jiraHttpClient.get(contains("NOVA-101"), anyString())).thenReturn(subtaskResp);
            when(jiraHttpClient.get(contains("NOVA-102"), anyString())).thenReturn(subtaskResp);
            when(confirmationService.isAvailable()).thenReturn(true);
            when(confirmationService.requestConfirmation(anyString(), any())).thenReturn(new ToolResult("ok"));

            tool.execute("{\"sourceIssueKey\":\"NOVA-100\",\"cloneSubtasks\":true}");

            verify(confirmationService).requestConfirmation(contains("Sub-Tasks"), any());
        }

        @Test
        @DisplayName("skips subtask when HTTP fetch returns non-200 and continues with rest")
        void skipsFailedSubtaskAndContinues() throws Exception {
            HttpResponse<String> parentResp  = mockResponseWith(200, SOURCE_WITH_SUBTASKS_JSON);
            HttpResponse<String> failResp    = mockResponseWith(500, "Internal Error");
            HttpResponse<String> subtaskResp = mockResponseWith(200, SUBTASK_JSON);

            when(jiraHttpClient.get(contains("NOVA-100"), anyString())).thenReturn(parentResp);
            when(jiraHttpClient.get(contains("NOVA-101"), anyString())).thenReturn(failResp);
            when(jiraHttpClient.get(contains("NOVA-102"), anyString())).thenReturn(subtaskResp);
            when(confirmationService.isAvailable()).thenReturn(true);
            when(confirmationService.requestConfirmation(anyString(), any())).thenReturn(new ToolResult("ok"));

            // Should not throw – failed subtask is skipped
            ToolResult result = tool.execute("{\"sourceIssueKey\":\"NOVA-100\",\"cloneSubtasks\":true}");

            assertThat(result.getText()).isEqualTo("ok");
        }

        @Test
        @DisplayName("does not fetch subtasks when cloneSubtasks is false (default)")
        void doesNotFetchSubtasksWhenDisabled() throws Exception {
            HttpResponse<String> parentResp = mockResponseWith(200, SOURCE_WITH_SUBTASKS_JSON);
            when(jiraHttpClient.get(anyString(), anyString())).thenReturn(parentResp);
            when(confirmationService.isAvailable()).thenReturn(false);

            tool.execute("{\"sourceIssueKey\":\"NOVA-100\"}");

            // Only the parent issue fetch, no subtask URLs
            verify(jiraHttpClient, times(1)).get(anyString(), anyString());
        }

        @SuppressWarnings("unchecked")
        private HttpResponse<String> mockResponseWith(int status, String body) {
            HttpResponse<String> resp = mock(HttpResponse.class);
            when(resp.statusCode()).thenReturn(status);
            lenient().when(resp.body()).thenReturn(body);
            return resp;
        }
    }
}
